solution: ```class TextEditor {
public:
    string s;
    int pos = 0;

    TextEditor() {}

    void addText(string text) {
        s.insert(pos, text);
        pos += text.size();
    }

    int deleteText(int k) {
        int rem = min(k, pos);
        s.erase(pos - rem, rem);
        pos -= rem;
        return rem;
    }

    string cursorLeft(int k) {
        pos = max(0, pos - k);
        int start = max(0, pos - 10);
        return s.substr(start, pos - start);
    }

    string cursorRight(int k) {
        pos = min((int)s.size(), pos + k);
        int start = max(0, pos - 10);
        return s.substr(start, pos - start);
    }
};
```
efficiency: HIGH
time complexity: O(k) per operation (k is length of text or parameter)
space complexity: O(n) where n is total characters stored
energy implications: LOW
explanation: Uses a single string and an integer cursor; each operation performs at most one string insertion/erase or substring extraction, all linear in the relevant parameter size.

